queries.formula:
let
    // 1. Carrega a query Reagendas_Filtro
    Reagendas = Reagendas_Filtro,

    // 2. Carrega a tabela de validações manuais
    Validacoes = Excel.CurrentWorkbook(){[Name="Validacao_BU"]}[Content],

    // 3. Garante que ambas as tabelas usam texto para "Num OS Final"
    ReagendasCorrigido = Table.TransformColumnTypes(Reagendas, {{"Num OS Final", type text}}),
    ValidacoesCorrigido = Table.TransformColumnTypes(Validacoes, {{"Num OS Final", type text}}),

    // 4. Remove duplicações de OS na tabela de validações
    ValidacoesUnicas = Table.Distinct(ValidacoesCorrigido, {"Num OS Final"}),

    // 5. Faz o merge pela coluna "Num OS Final"
    Merged = Table.NestedJoin(ReagendasCorrigido, {"Num OS Final"}, ValidacoesUnicas, {"Num OS Final"}, "ValInfo", JoinKind.LeftOuter),

    // 6. Expande as colunas de validação
    Expanded = Table.ExpandTableColumn(Merged, "ValInfo", {"Confere?", "Justificativa BU"}),

    // 7. Reordena as colunas no padrão desejado
    Reordered = Table.ReorderColumns(Expanded, {
        "Grupo - Justificativa", "Segmentação", "Diferença Horário", "De", "Para", "Data",
        "Justif Alteracao", "Obs Alteracao", "Porto Afetado", "R/N", "Num OS Final", "OS Cancelada",
        "Semana", "Confere?", "Justificativa BU"
    }),
    #"Added Custom" = Table.AddColumn(Reordered, "WeekDay", each Date.ToText(DateTime.Date([Data Alteracao]), "ddd", "en-US"))
in
    #"Added Custom"
